{
  "parameters": "z.object({ itemName: z.string().default("bread").describe("The name of the food item to consume, e.g., 'bread'"), maxCount: z.number().int().min(1).max(5).default(1).describe("The maximum number of food items to consume in this session") })",
  "executionArgs": {
    "itemName": "bread",
    "maxCount": 1
  },
  "code": "const normalize = function (name) {
  return String(name).trim().toLowerCase().replace(/^minecraft:/, '').replace(/\\s+/g, '_');
};
const pollMs = 50;
const eatTimeMs = 1700;
if (!bot.entity || bot.health <= 0) {
  return '<UNSAFE>: Bot is not alive.';
}
const targetName = normalize(args.itemName);
const getFoodItem = function () {
  return bot.inventory.items().find(function (item) {
    return normalize(item.name) === targetName || (item.displayName && normalize(item.displayName) === targetName);
  });
};
const foodItem = getFoodItem();
if (!foodItem) {
  return '<NO ITEM>: Could not find ' + args.itemName + ' in inventory.';
}
if (bot.food >= 20) {
  return '<STOPPED>: Food level is already full; cannot eat ' + args.itemName + '.';
}
startBackgroundSkill(bot, 'eat_bread', async function (token) {
  let count = 0;
  let currentlyUsing = false;
  try {
    while (count < args.maxCount && canContinueBotAction(bot, token)) {
      const item = getFoodItem();
      if (!item || bot.food >= 20) {
        break;
      }
      if (!await waitUntilWorldActive(bot, token, pollMs)) { return; }
      await bot.equip(item, 'hand');
      if (!await waitUntilWorldActive(bot, token, pollMs)) { return; }
      bot.activateItem();
      currentlyUsing = true;
      const finishedEating = await waitForActiveMs(bot, token, eatTimeMs, pollMs);
      bot.deactivateItem();
      currentlyUsing = false;
      if (!finishedEating) { return; }
      count++;
      if (!await waitForActiveMs(bot, token, 200, pollMs)) { return; }
    }
  } finally {
    if (currentlyUsing) {
      bot.deactivateItem();
    }
  }
});
return '<STARTED>: Commencing eating ' + args.itemName + ' up to ' + args.maxCount + ' times.';"
}

{
  "parameters": "z.object({ blockCount: z.number().int().min(1).max(10).default(4).describe("Number of oak planks to place as a barrier"), maxDistance: z.number().int().min(1).max(5).default(3).describe("How far from the bot to attempt placing blocks") })",
  "executionArgs": {
    "blockCount": 4,
    "maxDistance": 3
  },
  "code": "if (!bot.entity || bot.health <= 0) {
  return '<UNSAFE>: Bot is dead or missing entity.';
}
const planks = bot.inventory.items().find(i => i.name === 'oak_planks');
if (!planks || planks.count < args.blockCount) {
  return '<NO ITEM>: Insufficient oak planks. Have ' + (planks ? planks.count : 0) + ', need ' + args.blockCount + '.';
}
const pollMs = 50;
const placeDelayMs = 200;
startBackgroundSkill(bot, 'place_oak_planks_barrier', async function (token) {
  try {
    if (!await waitUntilWorldActive(bot, token, pollMs)) return;
    const directions = [
      new Vec3(1, 0, 0),
      new Vec3(-1, 0, 0),
      new Vec3(0, 0, 1),
      new Vec3(0, 0, -1)
    ];
    let placed = 0;
    for (const dir of directions) {
      if (placed >= args.blockCount) break;
      if (!canContinueBotAction(bot, token)) return;
      const targetPos = bot.entity.position.floored().add(dir);
      const currentItem = bot.inventory.items().find(i => i.name === 'oak_planks');
      if (!currentItem) break;
      const blockAtTarget = bot.blockAt(targetPos);
      if (!blockAtTarget || blockAtTarget.name !== 'air') continue;
      const neighbors = [
        targetPos.offset(0, -1, 0),
        targetPos.offset(1, 0, 0),
        targetPos.offset(-1, 0, 0),
        targetPos.offset(0, 0, 1),
        targetPos.offset(0, 0, -1)
      ];
      let referenceBlock = null;
      let faceVector = null;
      for (const n of neighbors) {
        const neighborBlock = bot.blockAt(n);
        if (neighborBlock && neighborBlock.name !== 'air') {
          referenceBlock = neighborBlock;
          faceVector = targetPos.minus(n);
          break;
        }
      }
      if (referenceBlock && faceVector) {
        if (!await waitUntilWorldActive(bot, token, pollMs)) return;
        await bot.equip(currentItem, 'hand');
        if (!await waitUntilWorldActive(bot, token, pollMs)) return;
        await bot.lookAt(referenceBlock.position.offset(0.5, 0.5, 0.5), true);
        if (!await waitUntilWorldActive(bot, token, pollMs)) return;
        try {
          await bot.placeBlock(referenceBlock, faceVector);
          placed++;
          await waitForActiveMs(bot, token, placeDelayMs, pollMs);
        } catch (err) {}
      }
    }
  } finally {
    bot.clearControlStates();
  }
});
return '<STARTED>: Placing up to ' + args.blockCount + ' oak planks as a barrier.';"
}
